--
-- Table structure for table "epicpay_customer_transactions"
--




CREATE TABLE IF NOT EXISTS "epicpay_customer_transactions" (
 "id" SERIAL PRIMARY KEY,
 "customer_id" INTEGER NOT NULL,
 "customer_source_id" INTEGER NOT NULL,
 "customer_subscription_id" INTEGER DEFAULT NULL,
 "church_id" INTEGER DEFAULT NULL,
 "campus_id" INTEGER DEFAULT NULL,
 "account_donor_id" INTEGER DEFAULT NULL,
 "batch_id" INTEGER DEFAULT NULL,
 "batch_method" VARCHAR(50) DEFAULT NULL,
 "batch_committed" VARCHAR(1) DEFAULT NULL,
 "batch_extra_data" TEXT DEFAULT NULL,
 "sub_total_amount" decimal(15,2) DEFAULT NULL,
 "total_amount" decimal(15,2) DEFAULT NULL,
 "fee" decimal(15,2) DEFAULT 0.00,
 "first_name" VARCHAR(100) DEFAULT NULL,
 "last_name" VARCHAR(100) DEFAULT NULL,
 "email" VARCHAR(100) DEFAULT NULL,
 "phone" VARCHAR(50) DEFAULT NULL,
 "address" VARCHAR(255) DEFAULT NULL,
 "note" VARCHAR(255) DEFAULT NULL,
 "country" VARCHAR(100) DEFAULT NULL,
 "city" VARCHAR(100) DEFAULT NULL,
 "apartment" VARCHAR(100) DEFAULT NULL,
 "state" VARCHAR(100) DEFAULT NULL,
 "zip" VARCHAR(100) DEFAULT NULL,
 "kiosk" VARCHAR(100) DEFAULT NULL,
 "member_id" VARCHAR(100) DEFAULT NULL,
 "giving_source" VARCHAR(50) DEFAULT NULL,
 "event_data" TEXT DEFAULT NULL,
 "giving_type" VARCHAR(50) DEFAULT NULL,
 "tags" VARCHAR(100) DEFAULT NULL,
 "multi_transaction_data" TEXT DEFAULT NULL,
 "multi_transaction_data_bkup" TEXT DEFAULT NULL,
 "request_data" TEXT DEFAULT NULL,
 "request_response" TEXT DEFAULT NULL,
 "refund_request" TEXT DEFAULT NULL,
 "refund_response" TEXT DEFAULT NULL,
 "created_from" VARCHAR(1) DEFAULT 'D',
 "src_account_type" VARCHAR(16) DEFAULT NULL,
 "epicpay_customer_id" VARCHAR(50) DEFAULT NULL,
 "epicpay_wallet_id" VARCHAR(50) DEFAULT NULL,
 "epicpay_transaction_type" VARCHAR(15) DEFAULT NULL,
 "epicpay_transaction_id" VARCHAR(50) DEFAULT NULL,
 "status" VARCHAR(1) DEFAULT 'U',
 "status_ach" VARCHAR(1) DEFAULT NULL,
 "fts_status_id" INTEGER DEFAULT NULL,
 "transaction_batch_id" VARCHAR(50) DEFAULT NULL,
 "manual_failed" SMALLINT DEFAULT NULL,
 "ach_reject_response" TEXT DEFAULT NULL,
 "migrated" VARCHAR(1) DEFAULT NULL,
 "migration_tr_id" VARCHAR(100) DEFAULT NULL,
 "created_at" TIMESTAMP DEFAULT NULL,
 "updated_at" TIMESTAMP DEFAULT NULL,
 "cancelled_at" TIMESTAMP DEFAULT NULL,
 "src" VARCHAR(50) DEFAULT NULL,
 "bank_type" VARCHAR(5) DEFAULT NULL,
 "template" VARCHAR(50) DEFAULT NULL,
 "is_fee_covered" SMALLINT NOT NULL DEFAULT 0,
 "from_domain" VARCHAR(64) DEFAULT NULL,
 "donor_ip" VARCHAR(45) DEFAULT NULL,
 "stripe_id" INTEGER DEFAULT NULL,
 "notfished_on_whook" SMALLINT DEFAULT NULL,
 "amount_upd" decimal(10,2) DEFAULT NULL,
 "campaign_id" INTEGER DEFAULT NULL,
 "amount_acum" decimal(15,2) DEFAULT 0.00,
 "fee_acum" decimal(15,2) DEFAULT 0.00,
 "trx_ret_id" INTEGER DEFAULT NULL,
 "trx_retorigin_id" INTEGER DEFAULT NULL,
 "trx_type" char(2) DEFAULT 'DO',
 "paysafeRef" VARCHAR(128) DEFAULT NULL,
 "manual_trx_type" char(2) DEFAULT NULL,
 "transaction_detail" text DEFAULT NULL,
 "invoice_id" INTEGER DEFAULT NULL,
 "user_wallet" VARCHAR(100) DEFAULT NULL,
 "exchange_rate" decimal(10,3) DEFAULT NULL,
 "crypto_amount" VARCHAR(30) DEFAULT NULL,
 "payment_link_id" INTEGER DEFAULT NULL,
 "receipt_file_uri_hash" VARCHAR(512) DEFAULT NULL)
);


