CREATE TABLE IF NOT EXISTS "epicpay_customers" (
 "id" SERIAL PRIMARY KEY,
 "email" VARCHAR(255) DEFAULT NULL,
 "first_name" VARCHAR(150) DEFAULT NULL,
 "last_name" VARCHAR(150) DEFAULT NULL,
 "church_id" INTEGER DEFAULT NULL,
 "account_donor_id" INTEGER DEFAULT NULL,
 "epicpay_customer_id" VARCHAR(50) DEFAULT NULL,
 "request_data" TEXT DEFAULT NULL,
 "request_response" TEXT DEFAULT NULL,
 "request_bank" TEXT DEFAULT NULL,
 "request_response_bank" TEXT DEFAULT NULL,
 "status" VARCHAR(1) DEFAULT 'U',
 "migrated" VARCHAR(1) DEFAULT NULL,
 "created_at" TIMESTAMP DEFAULT NULL,
 "updated_at" TIMESTAMP DEFAULT NULL,
 "from_stripemigration_sid" INTEGER DEFAULT NULL,
 "from_stripemigration_metadata" text DEFAULT NULL,
 "done_temp" SMALLINT DEFAULT NULL,
 "from_stripemigration_onetime" SMALLINT DEFAULT NULL,
 "ispaysafe" SMALLINT DEFAULT NULL,
 "merchant_customer_id" VARCHAR(50) DEFAULT NULL,
 "billing_address" text DEFAULT NULL
);


